import { ListItem, Icon } from 'react-native-elements'
import React, { useEffect, useState } from 'react'





const Menu = () => {
    const list = [
        {
            title: 'Appointments',
            icon: 'av-timer'
        },
        {
            title: 'Trips',
            icon: 'flight-takeoff'
        },

    ]
    console.log(list)
return (

    < View >
{
    list.map((item, i) => (
        <ListItem key={i} bottomDivider>
            <Icon name={item.icon} />
            <ListItem.Content>
                <ListItem.Title>{item.title}</ListItem.Title>
            </ListItem.Content>
            <ListItem.Chevron />
        </ListItem>
    ))
}
</View >
)
}

export default Menu;
